package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintWithValidAppendable() throws IOException, NoSuchFieldException, IllegalAccessException {
        Appendable appendable = mock(Appendable.class);
        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);

        // Use reflection to access the private 'out' field of CSVPrinter
        Field outField = CSVPrinter.class.getDeclaredField("out");
        outField.setAccessible(true);
        Object out = outField.get(printer);

        // The printer should use the given appendable
        assertSame(appendable, out);
    }

    @Test
    void testPrintWithAppendableThatThrowsIOException() throws IOException {
        Appendable appendable = mock(Appendable.class);
        // mock append method to throw IOException when called
        doThrow(new IOException("mock IOException")).when(appendable).append(any(CharSequence.class));

        CSVPrinter printer = csvFormat.print(appendable);
        assertNotNull(printer);

        // Now attempt to print a record which will cause append to be called and throw IOException
        assertThrows(IOException.class, () -> printer.print("test"));
    }
}
